mapper.select:
select s.*, c.course_name as courseName,stu.student_name as studentName, c.term as term from score s
left join course c on s.course_id = c.id
left join student stu on s.student_id = stu.student_id


        and s.course_id = #{courseId}


        and s.student_id = #{studentId}


        and c.term like concat('%',#{term},'%')
